// shadcn
import { Button } from "@/components/ui/button";

// assets
import { ArrowRightIcon } from "lucide-react";

// constants
const items = [
  {
    id: 1,
    image: "https://cdn.uiable.com/block/portfolio4-1.png",
    title: "Breathe In",
    description: "Better a diamond with a flaw than a pebble without one.",
  },
  {
    id: 2,
    image: "https://cdn.uiable.com/block/portfolio4-2.png",
    title: "Clock Me",
    description: "Better a diamond with a flaw than a pebble without one.",
  },
  {
    id: 3,
    image: "https://cdn.uiable.com/block/portfolio5-3.png",
    title: "Stream Co",
    description: "Better a diamond with a flaw than a pebble without one.",
  },
];

//  ------------------------------ | PORTFOLIO 5 | ------------------------------  //

//  ------------------------------ | PORTFOLIO5 | ------------------------------  //

export default function Portfolio5() {
  return (
    <section className="py-20">
      <div className="container mx-auto px-4 sm:px-6 lg:px-8">
        {/* Centered header */}
        <div className="text-center mb-12 flex flex-col gap-3 max-w-sm mx-auto">
          <p className="text-primary text-lg font-semibold uppercase tracking-widest">
            Portfolio
          </p>
          <h2 className="text-foreground">
            Creative Solutions To Improve Your Business
          </h2>
        </div>

        {/* 3-column grid */}
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
          {items.map((item) => (
            <div key={item.id} className="flex flex-col gap-4">
              {/* Image */}
              <div className="rounded-2xl overflow-hidden h-96">
                <img
                  src={item.image}
                  alt={item.title}
                  className="w-full h-full object-cover"
                />
              </div>
              {/* Content below image */}
              <div className="flex items-start justify-between gap-4">
                <div className="flex flex-col gap-1">
                  <h5 className="text-foreground font-bold text-md">
                    {item.title}
                  </h5>
                  <p className="text-muted-foreground text-md">
                    {item.description}
                  </p>
                </div>
                <Button
                  variant="outline"
                  size="icon"
                  className="shrink-0 rounded-lg border-yellow-500 text-yellow-500 hover:bg-yellow-500 hover:text-white"
                >
                  <ArrowRightIcon className="size-5" />
                </Button>
              </div>
            </div>
          ))}
        </div>

        {/* Bottom CTA */}
        <div className="flex justify-center mt-12">
          <Button className="bg-primary text-primary-foreground px-8">
            View Portfolio
          </Button>
        </div>
      </div>
    </section>
  );
}
